@page "/inventory"
@rendermode InteractiveServer
@using InventoryApp.Services
@inject IEquipmentService EquipmentService
@inject PersistentComponentState PersistentState

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistSub;

    protected override async Task OnInitializedAsync()
    {
        // Try to restore data that was persisted during prerender.
        // If found, skip the service call entirely (avoids double-fetch).
        if (!PersistentState.TryTakeFromJson<List<EquipmentItem>>(
                "inventory", out var restored))
        {
            restored = await EquipmentService.GetAllAsync();
        }

        _items = restored;

        // During prerender, register a callback to persist the data
        // so the interactive circuit can pick it up without re-fetching.
        _persistSub = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("inventory", _items);
            return Task.CompletedTask;
        });
    }

    public void Dispose() => _persistSub.Dispose();
}

